    "format": "Return only JSON. No markdown. No commentary.",
    "root_keys": [
      "choices"
    ],
    "choice_count": 4,
    "valid_action_types": [
      "attack",
      "block_object",
      "gesture",
      "mixed",
      "move",
      "show_object",
      "silence",
      "speak",
      "spend_resource",
      "touch_object",
      "transfer_object",
      "use_object",
      "wait",
      "withhold_object"
    ],
    "choice_fields": [
      "branch_id",
      "ink_path",
      "choice_text",
      "action_type",
      "actor_intent_private",
      "observable_action",
      "spoken_text",
      "state_basis",
      "expected_consequence_surfaces",
      "training_hooks"
